1. Marina Control Tower (`backend/marina_operations.py`)

```python
from typing import Dict, Any, List, Optional
from datetime import datetime, timedelta
from enum import Enum
import json

class MarinaStatus(Enum):
    DOCKED = "docked"
    MAINTENANCE = "maintenance"
    DEPARTED = "departed"

class PermissionType(Enum):
    ENTRY = "entry_permit"
    EXIT = "exit_permit"
    MAINTENANCE = "maintenance_permit"

class MarinaControlTower:
    """
    Marina kontrol kulesi - giriş/çıkış ve izin yönetimi
    West Istanbul Marina Operation Regulations uyumlu
    """

    def __init__(self, db):
        self.db = db
        self.control_points = [
            "main_entrance", "dock_a", "dock_b", 
            "maintenance_yard", "fuel_station", "slipway"
        ]
        self.max_speed_limit = 3  # knots (E.1.10)

    async def process_boat_entry(self, boat_id: int, control_point: str, 
                               permit_type: str = "regular") -> Dict[str, Any]:
        """Tekne giriş işlemi - Marina kontrol kulesi"""

        # İzin kontrolü (E.1.1, E.1.2)
        permit = await self.check_entry_permit(boat_id, permit_type)

        if not permit["allowed"]:
            return {
                "status": "reddedildi",
                "reason": permit["reason"],
                "control_point": control_point
            }

        # Giriş kaydı oluştur
        entry_record = await self.create_entry_record(
            boat_id=boat_id,
            control_point=control_point,
            permit_type=permit_type
        )

        # Cache güncelle
        await self.update_boat_status(boat_id, "docked", control_point)

        # Bildirim gönder
        await self.send_notification(
            boat_id=boat_id,
            message=f"Tekneniz {control_point} noktasına giriş yaptı. Hoş geldiniz!",
            type="giriş_bildirimi"
        )

        return {
            "status": "izin_verildi",
            "entry_id": entry_record["id"],
            "control_point": control_point,
            "entry_time": entry_record["entry_time"]
        }

    async def check_entry_permit(self, boat_id: int, permit_type: str) -> Dict[str, Any]:
        """Giriş izni kontrolü - E.1.1, E.1.2 maddeleri"""

        # Ödeme durumu kontrolü (E.7.9)
        unpaid_invoices = await self.db.get_unpaid_invoices(boat_id)
        if unpaid_invoices:
            return {
                "allowed": False,
                "reason": f"{len(unpaid_invoices)} adet ödenmemiş fatura var"
            }

        # Sigorta kontrolü (E.2.1)
        insurance_status = await self.db.check_insurance(boat_id)
        if not insurance_status:
            return {
                "allowed": False,
                "reason": "Geçerli sigorta poliçesi bulunmamaktadır"
            }

        # Yer kontrolü (E.1.5)
        available_berths = await self.db.get_available_berths()
        if not available_berths:
            return {
                "allowed": False,
                "reason": "Uygun rıhtım yok"
            }

        return {
            "allowed": True,
            "reason": "Giriş izni verildi"
        }

    async def create_permission_request(self, boat_id: int, permission_type: str,
                                      start_date: str, end_date: str, reason: str) -> Dict[str, Any]:
        """İzin talebi oluştur - E.5.8, E.5.9 maddeleri"""

        # İzin kaydı oluştur
        permission = await self.db.create_permission_record({
            "boat_id": boat_id,
            "permission_type": permission_type,
            "start_date": start_date,
            "end_date": end_date,
            "reason": reason,
            "status": "bekliyor",
            "approved_by": None
        })

        # Marina yöneticisine bildirim
        await self.notify_marina_manager(
            f"Yeni izin talebi - Tekne {boat_id}, {permission_type}"
        )

        return permission
```

2. Billing Integration (`backend/billing_integration.py`)

```python
import aiohttp
from typing import Dict, Any
import xml.etree.ElementTree as ET
from datetime import datetime
import uuid

class EInvoiceIntegration:
    """
    E-fatura entegrasyonu - E.7.1 - E.7.8 maddeleri
    GİB (Gelir İdaresi Başkanlığı) uyumlu
    """

    def __init__(self, config: Dict[str, Any]):
        self.integrator_url = config["url"]
        self.username = config["username"]
        self.password = config["password"]
        self.test_mode = config.get("test_mode", True)

    async def create_electronic_invoice(self, invoice_data: Dict[str, Any]) -> Dict[str, Any]:
        """E-fatura oluştur ve gönder - GİB uyumlu"""

        invoice_uuid = str(uuid.uuid4())

        # UBL standardına göre XML oluştur
        xml_content = self._create_ubl_xml(invoice_data, invoice_uuid)

        # Entegratöre gönder
        response = await self._send_to_integrator(xml_content, invoice_uuid)

        return {
            "uuid": invoice_uuid,
            "status": response.get("status", "gönderildi"),
            "gtb_id": response.get("gtb_id"),
            "xml_path": f"/invoices/xml/{invoice_uuid}.xml",
            "pdf_path": f"/invoices/pdf/{invoice_uuid}.pdf"
        }

    def _create_ubl_xml(self, data: Dict[str, Any], uuid: str) -> str:
        """UBL XML oluştur - E.7.4, E.7.5 maddeleri"""

        return f'''<?xml version="1.0" encoding="UTF-8"?>
<Invoice xmlns="urn:oasis:names:specification:ubl:schema:xsd:Invoice-2">
    <cbc:ID>{data["invoice_number"]}</cbc:ID>
    <cbc:UUID>{uuid}</cbc:UUID>
    <cbc:IssueDate>{data["issue_date"]}</cbc:IssueDate>
    <cbc:InvoiceTypeCode>380</cbc:InvoiceTypeCode>
    <cbc:DocumentCurrencyCode>TRY</cbc:DocumentCurrencyCode>

    <!-- Satıcı - West Istanbul Marina -->
    <cac:AccountingSupplierParty>
        <cac:Party>
            <cac:PartyName>
                <cbc:Name>West Istanbul Marina İşletmeleri A.Ş.</cbc:Name>
            </cac:PartyName>
            <cac:PostalAddress>
                <cbc:StreetName>Yakuplu Mah. Hürriyet Bulvarı No:1</cbc:StreetName>
                <cbc:CityName>Beylikdüzü</cbc:CityName>
                <cbc:PostalZone>34524</cbc:PostalZone>
                <cac:Country>
                    <cbc:Name>Türkiye</cbc:Name>
                </cac:Country>
            </cac:PostalAddress>
        </cac:Party>
    </cac:AccountingSupplierParty>

    <!-- Alıcı -->
    <cac:AccountingCustomerParty>
        <cac:Party>
            <cac:PartyName>
                <cbc:Name>{data["customer_name"]}</cbc:Name>
            </cac:PartyName>
        </cac:Party>
    </cac:AccountingCustomerParty>

    <!-- Fatura satırları -->
    <cac:InvoiceLine>
        <cbc:ID>1</cbc:ID>
        <cbc:InvoicedQuantity unitCode="DAY">30</cbc:InvoicedQuantity>
        <cbc:LineExtensionAmount currencyID="TRY">{data["amount"]}</cbc:LineExtensionAmount>
        <cac:Item>
            <cbc:Name>Rıhtım Kiralama - {data["berth_number"]}</cbc:Name>
        </cac:Item>
        <cac:Price>
            <cbc:PriceAmount currencyID="TRY">{data["daily_rate"]}</cbc:PriceAmount>
        </cac:Price>
    </cac:InvoiceLine>

    <!-- Vergi toplamı -->
    <cac:TaxTotal>
        <cbc:TaxAmount currencyID="TRY">{data["tax_amount"]}</cbc:TaxAmount>
        <cac:TaxSubtotal>
            <cbc:TaxableAmount currencyID="TRY">{data["amount"]}</cbc:TaxableAmount>
            <cbc:TaxAmount currencyID="TRY">{data["tax_amount"]}</cbc:TaxAmount>
            <cac:TaxCategory>
                <cbc:Percent>20</cbc:Percent>
            </cac:TaxCategory>
        </cac:TaxSubtotal>
    </cac:TaxTotal>

    <!-- Toplam -->
    <cac:LegalMonetaryTotal>
        <cbc:TaxInclusiveAmount currencyID="TRY">{data["total_amount"]}</cbc:TaxInclusiveAmount>
        <cbc:PayableAmount currencyID="TRY">{data["total_amount"]}</cbc:PayableAmount>
    </cac:LegalMonetaryTotal>

</Invoice>'''
```

3. FastAPI Backend (`backend/fastapi_app.py`)

```python
from fastapi import FastAPI, HTTPException, Depends
from fastapi.middleware.cors import CORSMiddleware
from pydantic import BaseModel
from typing import List, Optional
import uvicorn
from datetime import datetime

app = FastAPI(
    title="West Istanbul Marina API",
    description="155.000 m² marina yönetim sistemi",
    version="1.0.0"
)

app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)

# Pydantic Modelleri
class BoatEntry(BaseModel):
    boat_id: int
    control_point: str
    permit_type: str = "regular"

class PermissionRequest(BaseModel):
    boat_id: int
    permission_type: str
    start_date: str
    end_date: str
    reason: str

class EInvoice(BaseModel):
    invoice_number: str
    owner_id: int
    boat_id: int
    amount: float
    issue_date: str
    due_date: str

# Marina operasyonları
@app.post("/api/marina/entry")
async def process_entry(entry: BoatEntry):
    """Tekne giriş işlemi"""
    from marina_operations import MarinaControlTower
    tower = MarinaControlTower()
    result = await tower.process_boat_entry(
        entry.boat_id, 
        entry.control_point, 
        entry.permit_type
    )
    return result

@app.post("/api/marina/exit")
async def process_exit(boat_id: int, control_point: str):
    """Tekne çıkış işlemi"""
    from marina_operations import MarinaControlTower
    tower = MarinaControlTower()
    result = await tower.process_boat_exit(boat_id, control_point)
    return result

@app.get("/api/marina/status")
async def get_marina_status():
    """Marina genel durumu"""
    from marina_operations import MarinaControlTower
    tower = MarinaControlTower()
    return await tower.get_marina_status()

# İzin sistemi
@app.post("/api/permissions")
async def create_permission(permission: PermissionRequest):
    """İzin talebi oluştur"""
    from marina_operations import MarinaControlTower
    tower = MarinaControlTower()
    result = await tower.create_permission_request(
        permission.boat_id,
        permission.permission_type,
        permission.start_date,
        permission.end_date,
        permission.reason
    )
    return result

# E-fatura sistemi
@app.post("/api/invoices/electronic")
async def create_electronic_invoice(invoice: EInvoice):
    """E-fatura oluştur"""
    from billing_integration import EInvoiceIntegration

    integrator = EInvoiceIntegration({
        "url": "https://efatura.integrator.com/api",
        "username": "marina_user",
        "password": "marina_pass",
        "test_mode": True
    })

    result = await integrator.create_electronic_invoice(invoice.dict())
    return result

# Marina bilgileri
@app.get("/api/info/regulations")
async def get_regulations():
    """Marina işletme yönetmeliği"""
    return {
        "title": "West Istanbul Marina Operation Regulations",
        "version": "2024",
        "total_area": "155.000 m²",
        "berth_capacity": 500,
        "sections": [
            "A. PURPOSE",
            "B. SCOPE", 
            "C. DEFINITIONS",
            "D. MANDATE OF THE MARINA MANAGER",
            "E. PRINCIPLES APPLYING TO YACHTS AND YACHT OWNERS",
            "F. GENERAL RULES",
            "G. USE OF LAND VEHICLES",
            "H. TERMINATION",
            "I. MISCELLANEOUS",
            "J. NOTIFICATIONS",
            "K. DISPUTES"
        ]
    }

@app.get("/api/info/capacity")
async def get_capacity():
    """Marina kapasite bilgileri"""
    return {
        "total_area_sqm": 155000,
        "berth_capacity": 500,
        "dry_dock_capacity": 100,
        "crane_capacity_tons": 50,
        "services": [
            "electricity", "water", "fuel", "waste", 
            "wifi", "security", "camera_systems"
        ]
    }

# Sağlık kontrolü
@app.get("/api/health")
async def health_check():
    """Sistem sağlık durumu"""
    return {
        "status": "healthy",
        "database": "connected",
        "redis": "connected",
        "marina_operations": "active",
        "timestamp": datetime.now().isoformat()
    }

if __name__ == "__main__":
    uvicorn.run(app, host="0.0.0.0", port=8000)
```

