        // Fatura oluştur
        async function generateInvoice() {
            const boatId = prompt('Tekne ID girin:');
            if (boatId) {
                try {
                    const response = await fetch('/api/invoices/electronic', {
                        method: 'POST',
                        headers: {'Content-Type': 'application/json'},
                        body: JSON.stringify({
                            invoice_number: 'INV-' + Date.now(),
                            owner_id: 1,
                            boat_id: parseInt(boatId),
                            amount: 1500.00,
                            issue_date: new Date().toISOString().split('T')[0],
                            due_date: new Date(Date.now() + 30*24*60*60*1000).toISOString().split('T')[0]
                        })
                    });
                    const result = await response.json();
                    addLogEntry('FATURA', `E-fatura oluşturuldu: ${result.uuid}`);
                } catch (error) {
                    addLogEntry('HATA', 'Fatura oluşturulamadı: ' + error.message);
                }
            }
        }

        // Log ekle
        function addLogEntry(type, message) {
            const logPanel = document.getElementById('log-panel');
            const time = new Date().toLocaleTimeString();
            const entry = document.createElement('div');
            entry.className = 'log-entry';
            entry.innerHTML = `
                <span class="log-time">[${time}]</span>
                <span class="log-type">${type}</span>
                ${message}
            `;
            logPanel.insertBefore(entry, logPanel.firstChild);

            // Sadece son 50 log'u tut
            while (logPanel.children.length > 50) {
                logPanel.removeChild(logPanel.lastChild);
            }
        }

        // Başlangıç
        refreshStatus();
        setInterval(refreshStatus, 30000); // Her 30 saniyede bir güncelle
